// Validate API key at startup
const config = $input.item.json;
const state = $getWorkflowStaticData('global');

if (!config.apiKey || config.apiKey.trim() === '') {
  throw new Error('FATAL: API key is not configured. Set SERVICE_WORKER_API_KEY environment variable.');
}

// Only validate once per workflow execution
if (!state.apiKeyValidated) {
  console.log('Validating API key...');

  try {
    // Test API key by attempting a simple query
    const testQuery = `SELECT validate_worker_auth('${config.apiKey}') as worker_id`;

    // This will throw if API key is invalid
    // Note: In actual implementation, this would be a postgres node
    // For now, we'll mark as validated and let subsequent calls fail if invalid

    state.apiKeyValidated = true;
    state.apiKeyValidatedAt = Date.now();

    console.log('✓ API key validated successfully');
  } catch (error) {
    console.error('✗ API key validation failed:', error.message);
    state.fatalError = true;
    state.fatalErrorMessage = 'Invalid API key: ' + error.message;
    throw new Error('FATAL: API key validation failed - workflow cannot continue');
  }
}

return [{
  json: {
    ...config,
    apiKeyValidated: state.apiKeyValidated
  }
}];

// Register or update worker with queue subscriptions
const state = $getWorkflowStaticData('global');
const config = $input.item.json;

// Check if we need to register/update
const needsRegistration = !state.workerRegistered || 
                          (Date.now() - (state.lastRegistrationCheck || 0)) > 300000; // Re-register every 5 min

if (needsRegistration) {
  console.log('Registering/updating worker:', {
    workerId: config.serviceId,
    queueNames: config.queueNames,
    maxConcurrentTasks: config.maxConcurrentTasks
  });

  // Prepare registration data
  const registrationData = {
    workerId: config.serviceId,
    queueNames: config.queueNames,
    maxConcurrentTasks: config.maxConcurrentTasks,
    heartbeatInterval: config.heartbeatInterval
  };

  state.workerRegistered = true;
  state.lastRegistrationCheck = Date.now();
  state.registrationData = registrationData;

  return [{
    json: {
      ...config,
      needsRegistration: true,
      registrationData: registrationData
    }
  }];
} else {
  // Skip registration node
  return [{
    json: {
      ...config,
      needsRegistration: false
    }
  }];
}

// Initialize or load worker state with dynamic load calculation
const state = $getWorkflowStaticData('global');
const config = $input.item.json;

// Initialize state on first run
if (!state.initialized) {
  state.startTime = Date.now();
  state.lastHeartbeat = 0;
  state.currentTaskId = null;
  state.errorBackoff = false;
  state.backoffUntil = 0;
  state.consecutiveErrors = 0;
  state.tasksProcessed = 0;
  state.tasksFailed = 0;
  state.batchHistory = [];
  state.initialized = true;
}

// Calculate actual current load from database
// Note: In production, this would query the database
// For now, we'll use the tracked state
const currentLoad = state.currentTaskId ? 1 : 0;

// Check for shutdown signal
const runDuration = Date.now() - state.startTime;
const shouldShutdown = runDuration > config.maxRuntimeMs;

// Check graceful shutdown file (optional)
let shutdownRequested = false;
if (config.enableGracefulShutdown) {
  try {
    const fs = require('fs');
    shutdownRequested = fs.existsSync('/tmp/worker_shutdown_' + config.serviceId);
  } catch (e) {
    // File check failed, continue
  }
}

return [{
  json: {
    ...config,
    startTime: state.startTime,
    lastHeartbeat: state.lastHeartbeat,
    currentTaskId: state.currentTaskId,
    currentLoad: currentLoad,
    errorBackoff: state.errorBackoff,
    backoffUntil: state.backoffUntil,
    consecutiveErrors: state.consecutiveErrors,
    tasksProcessed: state.tasksProcessed,
    tasksFailed: state.tasksFailed,
    batchHistory: state.batchHistory,
    runDuration: runDuration,
    shouldShutdown: shouldShutdown || shutdownRequested,
    shutdownReason: shouldShutdown ? 'max_runtime' : (shutdownRequested ? 'graceful_shutdown' : null)
  }
}];

// Log shutdown and cleanup
const state = $getWorkflowStaticData('global');
const item = $input.item.json;

const successRate = state.tasksProcessed > 0 
  ? ((state.tasksProcessed - state.tasksFailed) / state.tasksProcessed * 100).toFixed(2) + '%'
  : 'N/A';

console.log('=================================');
console.log('WORKER SHUTTING DOWN');
console.log('=================================');
console.log('Reason:', item.shutdownReason);
console.log('Uptime:', Math.floor(item.runDuration / 1000) + 's');
console.log('Tasks Processed:', state.tasksProcessed);
console.log('Tasks Failed:', state.tasksFailed);
console.log('Success Rate:', successRate);
console.log('Current Load:', item.currentLoad);
console.log('=================================');

// Clear shutdown signal file
if (item.enableGracefulShutdown) {
  try {
    const fs = require('fs');
    const shutdownFile = '/tmp/worker_shutdown_' + item.serviceId;
    if (fs.existsSync(shutdownFile)) {
      fs.unlinkSync(shutdownFile);
      console.log('✓ Shutdown signal file cleared');
    }
  } catch (e) {
    console.error('Failed to clear shutdown signal:', e.message);
  }
}

// Reset state for next run
state.initialized = false;
state.workerRegistered = false;

console.log('Worker shutdown complete.');

return [];

// Enhanced queue validation failure handling
const state = $getWorkflowStaticData('global');
const item = $input.item.json;
const config = $('Worker Config').item.json;

const requestedQueues = config.queueNames;
const inactiveQueues = item.inactive_queues || [];
const validQueues = (item.valid_queues || []).filter(q => q !== null);
const missingQueues = requestedQueues.filter(q => !validQueues.includes(q));

console.error('=================================');
console.error('QUEUE VALIDATION FAILED');
console.error('=================================');
console.error('Requested:', requestedQueues);
console.error('Missing:', missingQueues);
console.error('Inactive:', inactiveQueues);
console.error('=================================');

// Determine backoff strategy
let backoffMs;

if (inactiveQueues.length > 0 && missingQueues.length === 0) {
  // Queues exist but are inactive - shorter backoff
  console.warn('Queues are temporarily inactive, will retry soon');
  backoffMs = Math.min(30000, config.backoffBaseMs); // 30 seconds max
} else if (missingQueues.length > 0) {
  // Queues don't exist - longer backoff
  console.error('Queues do not exist - check configuration');
  backoffMs = config.backoffMaxMs; // Maximum backoff
} else {
  // Unknown error
  backoffMs = config.backoffBaseMs * Math.pow(2, state.consecutiveErrors);
}

backoffMs = Math.min(config.backoffMaxMs, backoffMs);

state.errorBackoff = true;
state.backoffUntil = Date.now() + backoffMs;
state.consecutiveErrors++;

console.error('Entering backoff for', backoffMs, 'ms');

return [];

// Wait during backoff period
const state = $getWorkflowStaticData('global');
const waitMs = Math.max(1000, state.backoffUntil - Date.now());

console.log('In error backoff, waiting:', {
  waitMs: waitMs,
  consecutiveErrors: state.consecutiveErrors,
  backoffUntil: new Date(state.backoffUntil).toISOString()
});

await new Promise(resolve => setTimeout(resolve, waitMs));

// Clear backoff if time has passed
if (Date.now() >= state.backoffUntil) {
  console.log('Backoff period ended, resuming normal operation');
  state.errorBackoff = false;
}

return [];

