  // Simulate batch processing
  await new Promise(resolve => setTimeout(resolve, 500));

  const durationMs = Date.now() - started;

  // Update batch history for lease prediction
  const state = $getWorkflowStaticData('global');
  state.batchHistory = state.batchHistory || [];
  state.batchHistory.push(durationMs);

  // Keep only last 10 batches for moving average
  if (state.batchHistory.length > 10) {
    state.batchHistory.shift();
  }

  console.log('  ✓ Batch', (batchIndex + 1), 'completed in', durationMs + 'ms');

  for (const item of items) {
    item.json.batchDurationMs = durationMs;
    item.json.batchIndex = batchIndex;
  }

  return items;
} catch (error) {
  console.error('  ✗ Batch', (batchIndex + 1), 'failed:', error.message);

  // Return error to trigger failure path
  return items.map(item => ({
    json: {
      ...item.json,
      error: {
        message: error.message,
        code: 'BATCH_PROCESSING_ERROR',
        batchIndex: batchIndex,
        timestamp: new Date().toISOString()
      }
    }
  }));
}

// Enhanced lease check with predictive extension
const items = $input.all();
const now = Date.now();
const state = $getWorkflowStaticData('global');

// Calculate predicted next batch duration using moving average
const batchHistory = state.batchHistory || [];
const avgBatchMs = batchHistory.length > 0
  ? batchHistory.reduce((a, b) => a + b, 0) / batchHistory.length
  : 5000; // Default 5s

// Use 95th percentile for safety (or max if < 5 samples)
const p95BatchMs = batchHistory.length >= 5
  ? batchHistory.sort((a, b) => b - a)[Math.floor(batchHistory.length * 0.05)]
  : Math.max(...batchHistory, avgBatchMs);

for (const item of items) {
  const taskData = item.json.taskData || {};
  const leaseExpiresAt = taskData.leaseExpiresAt || taskData.lease_expires_at || item.json.leaseExpiresAt || null;
  const remainingMs = leaseExpiresAt ? new Date(leaseExpiresAt).getTime() - now : null;

  // Dynamic buffer based on batch history
  const bufferMs = taskData.leaseBufferMs || Math.max(10000, p95BatchMs * 1.5);
  const thresholdMs = p95BatchMs + bufferMs;

  item.json.remainingLeaseMs = remainingMs;
  item.json.predictedBatchMs = p95BatchMs;
  item.json.leaseBufferMs = bufferMs;
  item.json.heartbeatThresholdMs = thresholdMs;
  item.json.shouldExtendLease = remainingMs === null ? true : remainingMs < thresholdMs;
  item.json.extendByInterval = taskData.extendByInterval || '5 minutes';
}

return items;

// Check if all batches are complete
const batchNode = $('Batch Units');
const isLastBatch = batchNode.context && batchNode.context.noItemsLeft;

if (isLastBatch) {
  console.log('  → All batches completed');
  return [{
    json: {
      ...$input.item.json,
      allBatchesComplete: true,
      totalBatchesProcessed: (batchNode.context.batchIndex || 0) + 1
    }
  }];
} else {
  // Continue to next batch
  return [];
}

