// Enhanced fail_task with exponential backoff and detailed context
const item = $input.item.json;
const error = item.error || {};
const attemptNumber = item.attemptNumber || 1;
const maxAttempts = item.maxAttempts || 3;
const config = $('Worker Config').item.json;
const state = $getWorkflowStaticData('global');

// Calculate exponential backoff delay
const baseMs = config.backoffBaseMs || 5000;
const maxMs = config.backoffMaxMs || 300000;
const retryDelayMs = Math.min(maxMs, baseMs * Math.pow(2, attemptNumber - 1));
const retryDelayInterval = Math.floor(retryDelayMs / 1000) + ' seconds';

// Determine if we should retry
const shouldRetry = attemptNumber < maxAttempts;

// Calculate execution time
const executionTimeMs = Date.now() - (state.taskStartTime || Date.now());

// Format error message with context
const errorContext = {
  message: error.message || 'Task failed',
  code: error.code || 'UNKNOWN_ERROR',
  attempt: attemptNumber,
  maxAttempts: maxAttempts,
  timestamp: new Date().toISOString(),
  executionTimeMs: executionTimeMs,
  taskName: item.taskName,
  queueName: item.queueName,
  workerId: config.serviceId,
  stack: error.stack?.substring(0, 500) // Truncate stack trace
};

// Add batch-specific context if available
if (item.batchIndex !== undefined) {
  errorContext.batchIndex = item.batchIndex;
  errorContext.totalUnits = item.totalUnits;
}

const errorMessage = JSON.stringify(errorContext);

console.error('  ✗ Task failed:', {
  taskId: item.taskId,
  error: error.message,
  willRetry: shouldRetry,
  nextRetryIn: shouldRetry ? retryDelayInterval : 'none'
});

return [{
  json: {
    ...item,
    errorMessage: errorMessage,
    retryDelay: retryDelayInterval,
    shouldRetry: shouldRetry
  }
}];

