// Update worker state and metrics after task completion
const state = $getWorkflowStaticData('global');
const item = $input.item.json;
const config = $('Worker Config').item.json;

// Clear current task
state.currentTaskId = null;
state.taskStartTime = null;

// Update metrics
if (item.error) {
  state.tasksFailed++;
} else {
  state.tasksProcessed++;
}

const totalTasks = state.tasksProcessed + state.tasksFailed;
const metricsInterval = config.metricsReportInterval || 50;

// Log detailed metrics periodically
if (totalTasks % metricsInterval === 0) {
  const successRate = state.tasksProcessed > 0
    ? ((state.tasksProcessed - state.tasksFailed) / state.tasksProcessed * 100).toFixed(2)
    : 0;

  const uptimeSeconds = Math.floor((Date.now() - state.startTime) / 1000);
  const uptimeFormatted = Math.floor(uptimeSeconds / 3600) + 'h ' + 
                          Math.floor((uptimeSeconds % 3600) / 60) + 'm ' + 
                          (uptimeSeconds % 60) + 's';

  console.log('=================================');
  console.log('WORKER METRICS REPORT');
  console.log('=================================');
  console.log('Tasks Processed:', state.tasksProcessed);
  console.log('Tasks Failed:', state.tasksFailed);
  console.log('Success Rate:', successRate + '%');
  console.log('Uptime:', uptimeFormatted);
  console.log('Queue Subscriptions:', config.queueNames.join(', '));
  console.log('Current Load:', item.currentLoad || 0);
  console.log('=================================');
}

return [];
